tactics.stateBefore:
n : ℕ
p : MvPolynomial (Fin n) ℝ
⊢ let l1 := fun x => ∑ i : Fin n, |x i|;
  let pEval := fun x => (MvPolynomial.eval₂Hom (RingHom.id ℝ) x) p;
  let f := fun r => sInf ((fun x => pEval x) '' {x | l1 x = r});
  (∀ R > 0, ∃ rR, ∀ r > rR, f r > R) → ∃ a, 0 < ↑a ∧ ∃ c, 0 < c ∧ Tendsto (fun r => r ^ (-↑a) * f r) atTop (𝓝 c)
